"""Product model for the e-commerce system."""
from dataclasses import dataclass, field


@dataclass
class Product:
    """Represents a product in the catalog."""
    product_id: str
    name: str
    price: float
    stock: int
    category: str = "general"
    sku: str = ""

    def __post_init__(self):
        if self.price < 0:
            raise ValueError(f"Price cannot be negative: {self.price}")
        if self.stock < 0:
            raise ValueError(f"Stock cannot be negative: {self.stock}")
        if not self.sku:
            self.sku = self.product_id.upper()

    def is_available(self, quantity: int = 1) -> bool:
        """Check if the given quantity is available in stock."""
        return self.stock >= quantity

    def to_dict(self) -> dict:
        return {
            "product_id": self.product_id,
            "name": self.name,
            "price": self.price,
            "stock": self.stock,
            "category": self.category,
            "sku": self.sku,
        }

    def __repr__(self) -> str:
        return f"Product({self.product_id!r}, {self.name!r}, ${self.price:.2f}, stock={self.stock})"

