"""Order model for the e-commerce system."""
from dataclasses import dataclass, field
from typing import Optional
import time


@dataclass
class OrderItem:
    """A single line item in an order."""
    product_id: str
    quantity: int
    unit_price: float

    @property
    def subtotal(self) -> float:
        return self.unit_price * self.quantity


@dataclass
class Order:
    """Represents a customer order."""
    order_id: str
    customer_id: str
    items: list = field(default_factory=list)
    status: str = "pending"
    created_at: float = field(default_factory=time.time)
    discount_applied: float = 0.0
    _raw_total: Optional[float] = field(default=None, repr=False)

    def add_item(self, product_id: str, quantity: int, unit_price: float):
        """Add a line item to the order."""
        self.items.append(OrderItem(product_id, quantity, unit_price))
        self._raw_total = None  # invalidate cache

    @property
    def raw_total(self) -> float:
        """Sum of all line items before discounts."""
        if self._raw_total is None:
            self._raw_total = sum(item.subtotal for item in self.items)
        return self._raw_total

    @property
    def total(self) -> float:
        """Final total after discounts."""
        return self.raw_total - self.discount_applied

    @property
    def item_count(self) -> int:
        """Total number of units across all line items."""
        return sum(item.quantity for item in self.items)

    def to_dict(self) -> dict:
        return {
            "order_id": self.order_id,
            "customer_id": self.customer_id,
            "status": self.status,
            "items": [{"product_id": i.product_id, "quantity": i.quantity,
                       "unit_price": i.unit_price, "subtotal": i.subtotal}
                      for i in self.items],
            "raw_total": self.raw_total,
            "discount_applied": self.discount_applied,
            "total": self.total,
        }

    def __repr__(self) -> str:
        return f"Order({self.order_id!r}, customer={self.customer_id!r}, total=${self.total:.2f})"

