"""Customer model for the e-commerce system."""
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class Customer:
    """Represents a customer account."""
    customer_id: str
    name: str
    email: str
    balance: float = 0.0
    tier: str = "standard"  # standard, silver, gold, platinum
    total_spent: float = 0.0
    order_count: int = 0

    TIERS = {
        "standard": {"min_spent": 0, "extra_discount": 0.0},
        "silver": {"min_spent": 500, "extra_discount": 0.02},
        "gold": {"min_spent": 1000, "extra_discount": 0.05},
        "platinum": {"min_spent": 5000, "extra_discount": 0.10},
    }

    def can_afford(self, amount: float) -> bool:
        """Check whether the customer has enough balance."""
        return self.balance >= amount

    def deduct(self, amount: float):
        """Deduct from customer balance after a successful order."""
        if not self.can_afford(amount):
            raise ValueError(f"Insufficient balance: {self.balance:.2f} < {amount:.2f}")
        self.balance -= amount
        self.total_spent += amount
        self.order_count += 1

    @property
    def tier_extra_discount(self) -> float:
        """Extra discount fraction for this customer's tier."""
        return self.TIERS.get(self.tier, {}).get("extra_discount", 0.0)

    def to_dict(self) -> dict:
        return {
            "customer_id": self.customer_id,
            "name": self.name,
            "email": self.email,
            "balance": self.balance,
            "tier": self.tier,
            "total_spent": self.total_spent,
            "order_count": self.order_count,
        }

    def __repr__(self) -> str:
        return f"Customer({self.customer_id!r}, {self.name!r}, balance=${self.balance:.2f})"

