"""Inventory service — manages product stock levels."""
from models.product import Product


class InventoryService:
    """Handles stock reservation and release for orders."""

    def __init__(self, products: dict):
        # products: dict of product_id -> Product
        self._products = products
        self._reservations = {}  # order_id -> {product_id: quantity}

    def check_availability(self, product_id: str, quantity: int) -> bool:
        """Return True if product has enough unreserved stock."""
        product = self._products.get(product_id)
        if product is None:
            return False
        reserved = sum(
            r.get(product_id, 0)
            for r in self._reservations.values()
        )
        return (product.stock - reserved) >= quantity

    def reserve(self, order_id: str, product_id: str, quantity: int):
        """Reserve stock for an order (does not decrement stock yet)."""
        if not self.check_availability(product_id, quantity):
            raise ValueError(
                f"Cannot reserve {quantity} of {product_id!r}: insufficient stock"
            )
        if order_id not in self._reservations:
            self._reservations[order_id] = {}
        self._reservations[order_id][product_id] = (
            self._reservations[order_id].get(product_id, 0) + quantity
        )

    def release(self, order_id: str):
        """Release any reservations held for an order."""
        self._reservations.pop(order_id, None)

    def commit(self, order_id: str):
        """Commit reservations — permanently deduct stock."""
        reservation = self._reservations.pop(order_id, {})
        for product_id, quantity in reservation.items():
            product = self._products[product_id]
            product.stock -= quantity

    def get_stock(self, product_id: str) -> int:
        """Return current (unreserved) stock level."""
        product = self._products.get(product_id)
        if product is None:
            return 0
        reserved = sum(
            r.get(product_id, 0)
            for r in self._reservations.values()
        )
        return product.stock - reserved

