"""Payment service — processes payments from customer accounts."""
from models.customer import Customer
from models.order import Order


class PaymentError(Exception):
    """Raised when payment processing fails."""
    pass


class PaymentService:
    """Handles payment deduction from customer accounts."""

    def __init__(self):
        self._transactions = []  # audit log

    def process(self, order: Order, customer: Customer, amount: float) -> dict:
        """Deduct amount from customer balance and record transaction.

        Raises PaymentError if customer cannot afford the amount.
        """
        if not customer.can_afford(amount):
            raise PaymentError(
                f"Customer {customer.customer_id!r} cannot afford "
                f"${amount:.2f} (balance: ${customer.balance:.2f})"
            )
        customer.deduct(amount)
        txn = {
            "order_id": order.order_id,
            "customer_id": customer.customer_id,
            "amount": amount,
            "new_balance": customer.balance,
        }
        self._transactions.append(txn)
        return txn

    def refund(self, order_id: str, customer: Customer, amount: float) -> dict:
        """Refund amount to customer balance."""
        customer.balance += amount
        customer.total_spent = max(0.0, customer.total_spent - amount)
        txn = {
            "order_id": order_id,
            "customer_id": customer.customer_id,
            "amount": -amount,
            "new_balance": customer.balance,
        }
        self._transactions.append(txn)
        return txn

    @property
    def transaction_count(self) -> int:
        return len(self._transactions)
